{"content":"import torch


def torch_kernel(input_tensor, kernel_tensor, params=None):
    """PyTorch reference implementation for conv2d

    Args:
        input_tensor: Input tensor in NCHW format
        kernel_tensor: Kernel/weight tensor
        params: Optional parameters object with stride and padding attributes

    Returns:
        Output tensor from conv2d operation
    """
    # Extract stride and padding from params if provided, use defaults otherwise
    if params is not None and hasattr(params, 'stride'):
        stride = params.stride
    else:
        stride = 3

    if params is not None and hasattr(params, 'padding'):
        padding = params.padding
    else:
        padding = 0

    # Debug: print parameters for troubleshooting
    if stride != 3 or padding != 0:
        print(f"DEBUG torch_kernel: stride={stride}, padding={padding}, input={input_tensor.shape}")

    output = torch.nn.functional.conv2d(
        input_tensor, kernel_tensor, stride=stride, padding=padding
    )

    if stride != 3 or padding != 0:
        print(f"DEBUG output shape: {output.shape}")

    return output
